// n8n-marcin/13-auto-sugestie.json — Znajdz Tematy
// Purpose: Query Qdrant for recent articles, find 'postable' topics via AI
// NOT for: generating actual FB posts (that's FB Post Generator)

const qdrantUrl = 'http://qdrant:6333';
const geminiKey = $env.GEMINI_API_KEY || '';

// 1. Get articles from last 48h (wider window for weekends)
const now = new Date();
const cutoff = new Date(now.getTime() - 48 * 3600000).toISOString();

let articles = [];
try {
  const scrollResult = await this.helpers.httpRequest({
    method: 'POST',
    url: qdrantUrl + '/collections/krasnik_news/points/scroll',
    body: {
      limit: 50, with_payload: true, with_vector: false,
      filter: {
        must_not: [
          { key: 'category', match: { value: 'briefing' } },
          { key: 'category', match: { value: 'briefing-index' } },
          { key: 'category', match: { value: 'marcin-preference' } },
          { key: 'category', match: { value: 'marcin-style-feedback' } },
          { key: 'category', match: { value: 'marcin-last-post' } },
          { key: 'category', match: { value: 'sesja-rady-notified' } },
          { key: 'category', match: { value: 'bip-przetarg-notified' } }
        ]
      }
    },
    json: true
  });
  articles = (scrollResult.result?.points || []).map(p => p.payload);
} catch (e) { console.log('Qdrant scroll error:', e.message); }

// Sort by date descending, take most recent
articles.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
const recent = articles.slice(0, 30);

if (recent.length < 3) {
  return [{ json: { skip: true, reason: 'Za mało artykułów: ' + recent.length } }];
}

// 2. Get last post (avoid suggesting same topic)
let lastPostTopic = '';
try {
  const lastResult = await this.helpers.httpRequest({
    method: 'POST',
    url: qdrantUrl + '/collections/krasnik_news/points/scroll',
    body: {
      limit: 1, with_payload: true, with_vector: false,
      filter: { must: [{ key: 'category', match: { value: 'marcin-last-post' } }] }
    },
    json: true
  });
  lastPostTopic = lastResult.result?.points?.[0]?.payload?.generated_post?.substring(0, 200) || '';
} catch (e) {}

// 3. Ask Gemini to pick top 3 postable topics
const articleList = recent.map((a, i) => `${i + 1}. [${a.source || '?'}] ${a.title || a.description?.substring(0, 100) || '?'} (${a.date || '?'})`).join('\n');

const prompt = `Jesteś social media managerem powiatu kraśnickiego. Z poniższych artykułów wybierz DOKŁADNIE 3 najlepsze do posta na Facebook.

KRYTERIA:
- Temat interesujący dla mieszkańców powiatu kraśnickiego
- Pozytywne lub ważne informacje (inwestycje, wydarzenia, sukcesy, sport)
- Unikaj powtarzania tematu ostatniego posta: "${lastPostTopic.substring(0, 100)}"
- Preferuj: lokalne wydarzenia, decyzje rady, sport, edukacja, kultura

ARTYKUŁY:
${articleList}

ODPOWIEDZ DOKŁADNIE W FORMACIE (3 linie, każda: numer | tytuł | dlaczego):
1|Tytuł artykułu|Dlaczego warto (1 zdanie)
2|Tytuł artykułu|Dlaczego warto (1 zdanie)
3|Tytuł artykułu|Dlaczego warto (1 zdanie)`;

let suggestions = '';
try {
  const aiResult = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-lite-latest:generateContent?key=' + geminiKey,
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.3, maxOutputTokens: 500 }
    },
    json: true
  });
  suggestions = aiResult.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) { console.log('Gemini error:', e.message); }

if (!suggestions) {
  return [{ json: { skip: true, reason: 'Gemini nie zwrócił sugestii' } }];
}

// 4. Format WhatsApp message
const lines = suggestions.trim().split('\n').filter(l => l.includes('|'));
let msg = '💡 *Sugestie postów FB na dziś:*\n\n';
for (const line of lines) {
  const parts = line.split('|').map(s => s.trim());
  if (parts.length >= 3) {
    msg += `*${parts[0]}.* ${parts[1]}\n   → ${parts[2]}\n\n`;
  }
}
msg += 'Odpisz numerem, np. *1* lub *1, 3* 👍';

return [{ json: { skip: false, message: msg, articleCount: recent.length, suggestionsRaw: suggestions } }];
